// --- Build the IChatClient via MEAI + OpenAI provider ---
var openAiClient = new OpenAIClient(apiKey);
IChatClient chatClient = openAiClient.GetChatClient(modelId).AsIChatClient();

// --- Create tools and agent ---
using var loggerFactory = LoggerFactory.Create(b => b.AddConsole().SetMinimumLevel(LogLevel.Warning));
var tools = new ResearchTools();

var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a research agent. Your job is to research a topic thoroughly using
        the available tools. Follow this process:
        1. Search the web for information on the given topic using multiple queries.
        2. Take notes on key findings from each search using the note-taking tool.
        3. After gathering enough information (at least 3 searches), retrieve all
           notes and produce a comprehensive summary that synthesizes your findings.
        Always cite where you found information. Be thorough but concise.
        """,
    name: "ResearchAgent",
    description: "An agent that researches topics by searching the web and taking notes.",
