 /// <summary>
 /// Provides web search and note-taking tools for the research agent.
 /// </summary>
 sealed class ResearchTools
 {
     private readonly List<string> _notes = [];
     private readonly HttpClient _httpClient = new();

     [Description("Search the web for information on a query. Returns search result snippets.")]
     public async Task<string> SearchWeb(
         [Description("The search query to look up")] string query,
         CancellationToken cancellationToken = default)
     {
         Console.ForegroundColor = ConsoleColor.DarkGray;
         Console.WriteLine($"  🔍 Searching: \"{query}\"");
         Console.ResetColor();

         try
         {
             // Use DuckDuckGo Lite (HTML) as a simple, no-API-key search
             var encoded = Uri.EscapeDataString(query);
             var url = $"https://lite.duckduckgo.com/lite/?q={encoded}";

             using var request = new HttpRequestMessage(HttpMethod.Get, url);
             request.Headers.UserAgent.ParseAdd(
                 "Mozilla/5.0 (compatible; ResearchAgent/1.0)");

             using var response = await _httpClient.SendAsync(request, cancellationToken);
             var html = await response.Content.ReadAsStringAsync(cancellationToken);

             var results = ParseSearchResults(html);
             return results.Length > 0
                 ? results
                 : $"No results found for '{query}'. Try a different search query.";
         }
         catch (Exception ex)
         {
             return $"Search failed: {ex.Message}. Try a different query.";
         }
     }

     [Description("Save a research note. Use this to record key findings from searches.")]
     public string TakeNote(
         [Description("The note content to save")] string note,
         [Description("The source or context for this note")] string source)
     {
         Console.ForegroundColor = ConsoleColor.DarkGray;
         Console.WriteLine($"  📝 Note saved from: {source}");
         Console.ResetColor();

         _notes.Add($"[Source: {source}] {note}");
         return $"Note #{_notes.Count} saved successfully.";
     }

     [Description("Retrieve all research notes taken so far.")]
     public string GetNotes()
     {
         if (_notes.Count == 0)
         {
             return "No notes have been taken yet.";
         }

         var sb = new StringBuilder();
         sb.AppendLine($"=== Research Notes ({_notes.Count} total) ===");
         for (int i = 0; i < _notes.Count; i++)
         {
             sb.AppendLine($"{i + 1}. {_notes[i]}");
         }

         return sb.ToString();
     }

     public void ClearNotes() => _notes.Clear();

     private static string ParseSearchResults(string html)
     {
         var sb = new StringBuilder();
         int count = 0;

         // Extract text snippets between result markers in DuckDuckGo Lite HTML
         var snippetTag = "<td class=\"result-snippet\">";
         var linkTag = "<a rel=\"nofollow\" href=\"";
         int pos = 0;

         while (count < 5 && pos < html.Length)
         {
             // Find next link
             int linkStart = html.IndexOf(linkTag, pos, StringComparison.Ordinal);
             if (linkStart < 0) break;

             linkStart += linkTag.Length;
             int linkEnd = html.IndexOf('"', linkStart);
             if (linkEnd < 0) break;

             var link = html[linkStart..linkEnd];

             // Find snippet after this link
             int snippetStart = html.IndexOf(snippetTag, linkEnd, StringComparison.Ordinal);
             if (snippetStart < 0)
             {
                 pos = linkEnd + 1;
                 continue;
             }

             snippetStart += snippetTag.Length;
             int snippetEnd = html.IndexOf("</td>", snippetStart, StringComparison.Ordinal);
             if (snippetEnd < 0) break;

             var snippet = StripHtmlTags(html[snippetStart..snippetEnd]).Trim();
             if (snippet.Length > 0)
             {
                 count++;
                 sb.AppendLine($"Result {count}: {snippet}");
                 sb.AppendLine($"  URL: {link}");
                 sb.AppendLine();
             }

             pos = snippetEnd + 1;
         }

         return sb.ToString();
     }

     private static string StripHtmlTags(string html)
     {
         var sb = new StringBuilder();
         bool inTag = false;
         foreach (var ch in html)
         {
             if (ch == '<') { inTag = true; continue; }
             if (ch == '>') { inTag = false; continue; }
             if (!inTag) sb.Append(ch);
         }

         return sb.ToString();
     }
 }
